import novamind_api as nm

# Check discovered groups
overview = nm.market.get_market_overview()
print('Discovered Groups:')
for g in overview.get('groups', []):
    print(f"  {g['group_id']}: info_level={g.get('info_level', 0)}, subs={g.get('subscribers', 0)}")

# Check S2 insights
try:
    s2_insights = nm.market.get_group_insights('S2')
    print('\nS2 Insights:')
    print(f"  Quality floors: {s2_insights.get('quality_floors', {})}")
except Exception as e:
    print(f"S2 insights error: {e}")

# Check S3 insights
try:
    s3_insights = nm.market.get_group_insights('S3')
    print('\nS3 Insights:')
    print(f"  Quality floors: {s3_insights.get('quality_floors', {})}")
except Exception as e:
    print(f"S3 insights error: {e}")

# Check network effects
print('\nNetwork Effects (leads per 1000 subs/day):')
for source in ['S1', 'S2', 'S3']:
    try:
        insights = nm.market.get_group_insights(source)
        for target, rate in insights.get('leads_per_1000_subscribers', {}).items():
            if rate > 0:
                print(f"  {source} -> {target}: {rate:.4f}")
    except:
        pass
